  1	import * as React from 'react';
  2	import { getName, getNamespace } from '@odf/shared/selectors';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import {
  5	  GreenCheckCircleIcon,
  6	  RedExclamationCircleIcon,
  7	  useK8sWatchResources,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Dropdown,
 11	  DropdownItem,
 12	  DropdownList,
 13	  MenuToggle,
 14	  MenuToggleElement,
 15	} from '@patternfly/react-core';
 16	import {
 17	  Flex,
 18	  FlexItem,
 19	  HelperText,
 20	  HelperTextItem,
 21	} from '@patternfly/react-core';
 22	import {
 23	  DRActionType,
 24	  MANAGED_CLUSTER_CONDITION_AVAILABLE,
 25	  ReplicationType,
 26	} from '../../../../constants';
 27	import {
 28	  getDRClusterResourceObj,
 29	  getManagedClusterResourceObj,
 30	} from '../../../../hooks';
 31	import { ACMManagedClusterKind, DRClusterKind } from '../../../../types';
 32	import { DateTimeFormat } from '../failover-relocate-modal-body';
 33	import { ErrorMessageType } from './error-messages';
 34	import {
 35	  FailoverAndRelocateState,
 36	  FailoverAndRelocateAction,
 37	  FailoverAndRelocateType,
 38	  TargetClusterType,
 39	  ModalFooterStatus,
 40	} from './reducer';
 41	
 42	export enum DRClusterStatus {
 43	  FENCED = 'Fenced',
 44	  UNFENCED = 'Unfenced',
 45	  AVAILABLE = 'Available',
 46	}
 47	
 48	const getAvailableCondition = (managedCluster: ACMManagedClusterKind) =>
 49	  managedCluster?.status?.conditions?.find(
 50	    (condition) =>
 51	      condition?.type === MANAGED_CLUSTER_CONDITION_AVAILABLE &&
 52	      condition.status === 'True'
 53	  );
 54	
 55	const TargetClusterStatus: React.FC<TargetClusterStatusProps> = ({
 56	  isClusterAvailable,
 57	}) => {
 58	  return isClusterAvailable ? (
 59	    <GreenCheckCircleIcon />
 60	  ) : (
 61	    <RedExclamationCircleIcon />
 62	  );
 63	};
 64	
 65	const resources = {
 66	  drClusters: getDRClusterResourceObj(),
 67	  managedClusters: getManagedClusterResourceObj(),
 68	};
 69	
 70	export const TargetClusterSelector: React.FC<TargetClusterSelectorProps> = ({
 71	  state,
 72	  dispatch,
 73	}) => {
 74	  const { t } = useCustomTranslation();
 75	  const response =
 76	    useK8sWatchResources<TargetClusterWatchResourceType>(resources);
 77	
 78	  const { selectedDRPolicy } = state;
 79	
 80	  const {
 81	    data: drClusters,
 82	    loaded: drClustersLoaded,
 83	    loadError: drClustersLoadError,
 84	  } = response?.drClusters;
 85	
 86	  const {
 87	    data: managedClusters,
 88	    loaded: managedClustersLoaded,
 89	    loadError: managedClustersLoadError,
 90	  } = response?.managedClusters;
 91	
 92	  const [isOpen, setOpen] = React.useState(false);
 93	
 94	  const drClusterList = React.useMemo(
 95	    () =>
 96	      drClustersLoaded && !drClustersLoadError
 97	        ? drClusters?.filter((drCluster) =>
 98	            selectedDRPolicy?.drClusters?.includes(getName(drCluster))
 99	          )
100	        : [],
101	    [drClusters, drClustersLoaded, drClustersLoadError, selectedDRPolicy]
102	  );
103	
104	  const managedClusterList = React.useMemo(
105	    () =>
106	      managedClustersLoaded && !managedClustersLoadError
107	        ? managedClusters?.filter((managedCluster) =>
108	            selectedDRPolicy?.drClusters?.includes(getName(managedCluster))
109	          )
110	        : [],
111	    [
112	      managedClusters,
113	      managedClustersLoaded,
114	      managedClustersLoadError,
115	      selectedDRPolicy,
116	    ]
117	  );
118	
119	  React.useLayoutEffect(() => {
120	    if (
121	      state.actionType === DRActionType.RELOCATE &&
122	      !!managedClusterList.length
123	    ) {
124	      const areBothClustersUp = managedClusterList.every(
125	        (managedCluster) => !!getAvailableCondition(managedCluster)
126	      );
127	      !areBothClustersUp &&
128	        dispatch({
129	          type: FailoverAndRelocateType.SET_ERROR_MESSAGE,
130	          payload: {
131	            managedClustersErrorMessage:
132	              ErrorMessageType.MANAGED_CLUSTERS_ARE_DOWN,
133	          },
134	        });
135	    }
136	  }, [managedClusterList, state.actionType, dispatch, t]);
137	
138	  const setErrorMessage = (errorMessage: ErrorMessageType) => {
139	    dispatch({
140	      type: FailoverAndRelocateType.SET_ERROR_MESSAGE,
141	      payload: {
142	        targetClusterErrorMessage: errorMessage,
143	      },
144	    });
145	  };
146	
147	  const setSelected = (selection: TargetClusterType) => {
148	    dispatch({
149	      type: FailoverAndRelocateType.SET_SELECTED_TARGET_CLUSTER,
150	      payload: selection,
151	    });
152	  };
153	
154	  const dropdownItems = React.useMemo(
155	    () =>
156	      managedClusterList.map((managedCluster, index) => (
157	        <DropdownItem
158	          data-test={`target-cluster-dropdown-item-${index}`}
159	          key={`selected-target-cluster-${getName(managedCluster)}`}
160	          value={getName(managedCluster)}
161	        >
162	          {getName(managedCluster)}
163	        </DropdownItem>
164	      )),
165	    [managedClusterList]
166	  );
167	
168	  const onSelect = (
169	    _event?: React.MouseEvent<Element, MouseEvent>,
170	    selection?: string | number
171	  ) => {
172	    const managedCluster = managedClusterList?.find(
173	      (cluster) => getName(cluster) === selection
174	    );
175	    // Select a target cluster to intiate failover or relocate
176	    // Check ACM managed cluster is available or not
177	    const condition = getAvailableCondition(managedCluster);
178	    let isClusterAvailable = !!condition;
179	    let isClusterFenced = true;
180	    let errorMessage = 0;
181	
182	    if (isClusterAvailable) {
183	      // Check DR fencing status for origin cluster
184	      const targetCluster = drClusterList.find(
185	        (drCluster) => getName(drCluster) === getName(managedCluster)
186	      );
187	      const originCluster = drClusterList.find(
188	        (drCluster) => getName(drCluster) !== getName(managedCluster)
189	      );
190	
191	      if (selectedDRPolicy.replicationType === ReplicationType.SYNC) {
192	        if (state.actionType === DRActionType.RELOCATE) {
193	          // Ensure origin and target both clusters are unfenced
194	          const isClustersUnfenced = drClusterList.every(
195	            (drCluster) =>
196	              DRClusterStatus.FENCED !==
197	              (drCluster?.status?.phase as DRClusterStatus)
198	          );
199	          errorMessage =
200	            !isClustersUnfenced && ErrorMessageType.SOME_CLUSTERS_ARE_FENCED;
201	        } else {
202	          // Ensure origin cluster is fenced
203	          const isClustersFenced =
204	            DRClusterStatus.FENCED ===
205	            (originCluster?.status?.phase as DRClusterStatus);
206	          const fencedErrorMessage =
207	            !isClustersFenced && ErrorMessageType.PRIMARY_CLUSTER_IS_NOT_FENCED;
208	          // Ensure target cluster is unfenced
209	          const isClusterUnFenced =
210	            DRClusterStatus.FENCED !==
211	            (targetCluster?.status?.phase as DRClusterStatus);
212	          const unFencedErrorMessage =
213	            !isClusterUnFenced && ErrorMessageType.TARGET_CLUSTER_IS_FENCED;
214	          errorMessage = fencedErrorMessage || unFencedErrorMessage;
215	        }
216	      }
217	    } else {
218	      errorMessage = ErrorMessageType.TARGET_CLUSTER_IS_NOT_AVAILABLE;
219	    }
220	    setSelected({
221	      clusterInfo: {
222	        clusterName: getName(managedCluster),
223	        clusterNamespace: getNamespace(managedCluster),
224	      },
225	      isClusterAvailable: isClusterAvailable && isClusterFenced,
226	      lastAvailableTime: condition?.lastTransitionTime,
227	    });
228	    setErrorMessage(errorMessage);
229	    setOpen(false);
230	  };
231	
232	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
233	    <MenuToggle
234	      ref={toggleRef}
235	      className="mco-subs-dr-action-body__dropdown--width"
236	      data-test="target-cluster-dropdown-toggle"
237	      isDisabled={
238	        !drClusterList.length ||
239	        !managedClusterList.length ||
240	        state.modalFooterStatus === ModalFooterStatus.FINISHED ||
241	        !!state.errorMessage.managedClustersErrorMessage
242	      }
243	      isExpanded={isOpen}
244	      onClick={() => setOpen((prev) => !prev)}
245	    >
246	      {!!Object.keys(state.selectedTargetCluster).length ? (
247	        <Flex>
248	          <FlexItem className="mco-subs-dr-action__target-cluster--width">
249	            {state.selectedTargetCluster?.clusterInfo?.clusterName}
250	          </FlexItem>
251	          <FlexItem>
252	            <TargetClusterStatus
253	              isClusterAvailable={
254	                state.selectedTargetCluster?.isClusterAvailable
255	              }
256	            />
257	          </FlexItem>
258	        </Flex>
259	      ) : (
260	        t('Select')
261	      )}
262	    </MenuToggle>
263	  );
264	
265	  return (
266	    <>
267	      <Dropdown
268	        className="mco-subs-dr-action-body__dropdown--width"
269	        isOpen={isOpen}
270	        onOpenChange={(open: boolean) => setOpen(open)}
271	        onSelect={onSelect}
272	        toggle={toggle}
273	      >
274	        <DropdownList>{dropdownItems}</DropdownList>
275	      </Dropdown>
276	      <HelperText>
277	        <HelperTextItem variant="indeterminate">
278	          {t('Last available: ')}
279	          <DateTimeFormat
280	            dateTime={state.selectedTargetCluster?.lastAvailableTime}
281	            className="pf-v6-u-display-inline-block pf-v6-u-ml-sm"
282	          />
283	        </HelperTextItem>
284	      </HelperText>
285	    </>
286	  );
287	};
288	
289	type TargetClusterSelectorProps = {
290	  state: FailoverAndRelocateState;
291	  dispatch: React.Dispatch<FailoverAndRelocateAction>;
292	};
293	
294	type TargetClusterWatchResourceType = {
295	  drClusters: DRClusterKind[];
296	  managedClusters: ACMManagedClusterKind[];
297	};
298	
299	type TargetClusterStatusProps = {
300	  isClusterAvailable: boolean;
301	};

